// FILTRAGEM DOS ARTIGOS DA SEMANA E PREPARAÇÃO DO CONTEXTO
const itens = $input.all().map(i => i.json);

// Filtra últimos 7 dias
const seteDiasAtras = new Date();
seteDiasAtras.setDate(seteDiasAtras.getDate() - 7);

const artigos = itens.filter(item => {
  if (!item.data_coleta) return false;
  const data = new Date(item.data_coleta);
  return data >= seteDiasAtras;
});

if (artigos.length === 0) {
  throw new Error('Nenhum artigo encontrado nos últimos 7 dias. Verifique se o Workflow 1 rodou esta semana.');
}

// Estatísticas da semana
const porCategoria = {};
const porSentimento = { positivo: 0, neutro: 0, negativo: 0 };
const oportunidades = [];

artigos.forEach(a => {
  const cat = a.categoria || 'Outros';
  porCategoria[cat] = (porCategoria[cat] || 0) + 1;
  const s = a.sentimento || 'neutro';
  if (porSentimento[s] !== undefined) porSentimento[s]++;
  if (a.oportunidade_startup && a.oportunidade_startup !== 'null') {
    oportunidades.push(a.oportunidade_startup);
  }
});

// Top 10 artigos por pontuação
const top10 = [...artigos]
  .sort((a, b) => (Number(b.pontuacao_relevancia) || 0) - (Number(a.pontuacao_relevancia) || 0))
  .slice(0, 10);

// Prepara contexto resumido para a IA
const contextoArtigos = top10.map((a, i) =>
  `[${i+1}] ${a.titulo}\nFonte: ${a.fonte} | Categoria: ${a.categoria} | Pontuação: ${a.pontuacao_relevancia}\nResumo: ${a.resumo}`
).join('\n\n');

const semanaFormatada = new Date().toLocaleDateString('pt-BR', { day: '2-digit', month: 'long', year: 'numeric' });

return [{
  json: {
    semana: semanaFormatada,
    total_artigos: artigos.length,
    top10,
    por_categoria: porCategoria,
    por_sentimento: porSentimento,
    oportunidades_unicas: [...new Set(oportunidades)].slice(0, 5),
    contexto_para_ia: contextoArtigos
  }
}];

// PARSE DA RESPOSTA DA IA E MONTAGEM DO OBJETO FINAL
const iaInput = $input.first().json;
const dadosSemana = $('Filtra e Prepara').first().json;

// Extrai e parseia o JSON da IA
const j = iaInput;
const texto = (
  j?.content?.[0]?.text ||
  j?.message?.content ||
  j?.choices?.[0]?.message?.content ||
  j?.text ||
  j?.output?.[0]?.content?.[0]?.text ||
  ''
).replace(/```json|```/g, '').trim();
let analise = {};
try {
  analise = JSON.parse(texto)
} catch(e) {
  analise = {
    resumo_executivo: 'Análise indisponível esta semana.',
    principais_tendencias: [],
    radar_startups: [],
    previsoes_proxima_semana: []
  };
}

// Monta HTML estilizado para email e arquivo local
const top5Html = dadosSemana.top10.slice(0, 5).map(a =>
  `<tr>
    <td style="padding:12px;border-bottom:1px solid #1e293b">
      <a href="${a.url}" style="color:#38bdf8;font-weight:600;text-decoration:none">${a.titulo}</a>
      <div style="color:#94a3b8;font-size:13px;margin-top:4px">${a.fonte} · ${a.categoria} · ⭐ ${a.pontuacao_relevancia}/10</div>
      <div style="color:#cbd5e1;font-size:13px;margin-top:4px">${a.resumo}</div>
    </td>
  </tr>`
).join('');

const tendenciasHtml = (analise.principais_tendencias || []).map(t =>
  `<div style="margin-bottom:20px;padding:16px;background:#1e293b;border-radius:8px;border-left:3px solid #38bdf8">
    <div style="color:#38bdf8;font-weight:700;margin-bottom:6px">📈 ${t.titulo}</div>
    <div style="color:#cbd5e1;font-size:14px">${t.analise}</div>
  </div>`
).join('');

const startupsHtml = (analise.radar_startups || []).map(s =>
  `<div style="margin-bottom:20px;padding:16px;background:#1e293b;border-radius:8px;border-left:3px solid #a78bfa">
    <div style="color:#a78bfa;font-weight:700;margin-bottom:6px">💼 ${s.oportunidade}</div>
    <div style="color:#cbd5e1;font-size:14px">${s.descricao}</div>
    <div style="color:#64748b;font-size:13px;margin-top:6px">⚡ ${s.por_que_agora}</div>
  </div>`
).join('');

const previsoesHtml = (analise.previsoes_proxima_semana || []).map(p =>
  `<div style="margin-bottom:16px;padding:14px;background:#1e293b;border-radius:8px;border-left:3px solid #34d399">
    <div style="color:#34d399;font-weight:600;margin-bottom:4px">🔮 ${p.previsao}</div>
    <div style="color:#94a3b8;font-size:13px">${p.base}</div>
  </div>`
).join('');

const categoriasHtml = Object.entries(dadosSemana.por_categoria)
  .sort((a, b) => b[1] - a[1])
  .map(([k, v]) => `<span style="display:inline-block;margin:4px;padding:4px 10px;background:#1e293b;border-radius:20px;color:#94a3b8;font-size:13px">${k}: ${v}</span>`)
  .join('');

const htmlCompleto = `<!DOCTYPE html>
<html lang="pt-BR">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Inteli AI Intelligence Hub — Semana de ${dadosSemana.semana}</title>
  <style>
    @import url('https://fonts.googleapis.com/css2?family=Space+Mono:wght@400;700&family=Inter:wght@300;400;600;700&display=swap');
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #020817; color: #e2e8f0; font-family: 'Inter', sans-serif; }
    .container { max-width: 700px; margin: 0 auto; padding: 40px 20px; }
    .header { text-align: center; padding: 40px 0; border-bottom: 1px solid #1e293b; margin-bottom: 40px; }
    .logo { font-family: 'Space Mono', monospace; font-size: 11px; color: #38bdf8; letter-spacing: 4px; text-transform: uppercase; margin-bottom: 16px; }
    h1 { font-size: 28px; font-weight: 700; color: #f8fafc; line-height: 1.3; }
    .subtitle { color: #64748b; font-size: 14px; margin-top: 8px; }
    .stat-row { display: flex; gap: 12px; margin-bottom: 40px; }
    .stat { flex: 1; background: #0f172a; border: 1px solid #1e293b; border-radius: 8px; padding: 16px; text-align: center; }
    .stat-num { font-size: 28px; font-weight: 700; color: #38bdf8; font-family: 'Space Mono', monospace; }
    .stat-label { font-size: 11px; color: #64748b; text-transform: uppercase; letter-spacing: 1px; margin-top: 4px; }
    .section { margin-bottom: 40px; }
    .section-title { font-family: 'Space Mono', monospace; font-size: 11px; color: #64748b; letter-spacing: 3px; text-transform: uppercase; margin-bottom: 16px; padding-bottom: 8px; border-bottom: 1px solid #1e293b; }
    .resumo { background: #0f172a; border: 1px solid #1e293b; border-radius: 8px; padding: 20px; color: #cbd5e1; line-height: 1.7; font-size: 15px; }
    table { width: 100%; border-collapse: collapse; background: #0f172a; border-radius: 8px; overflow: hidden; }
    .footer { text-align: center; padding-top: 40px; border-top: 1px solid #1e293b; color: #475569; font-size: 13px; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <div class="logo">Inteli AI Intelligence Hub</div>
      <h1>Relatório Semanal de IA</h1>
      <div class="subtitle">Semana de ${dadosSemana.semana}</div>
    </div>
    <div class="stat-row">
      <div class="stat"><div class="stat-num">${dadosSemana.total_artigos}</div><div class="stat-label">Artigos</div></div>
      <div class="stat"><div class="stat-num">${Object.keys(dadosSemana.por_categoria).length}</div><div class="stat-label">Categorias</div></div>
      <div class="stat"><div class="stat-num">${dadosSemana.oportunidades_unicas.length}</div><div class="stat-label">Oportunidades</div></div>
      <div class="stat"><div class="stat-num">${dadosSemana.por_sentimento.positivo}</div><div class="stat-label">Positivos</div></div>
    </div>
    <div class="section">
      <div class="section-title">Resumo Executivo</div>
      <div class="resumo">${analise.resumo_executivo}</div>
    </div>
    <div class="section">
      <div class="section-title">Principais Tendências</div>
      ${tendenciasHtml}
    </div>
    <div class="section">
      <div class="section-title">Top 5 Artigos da Semana</div>
      <table>${top5Html}</table>
    </div>
    <div class="section">
      <div class="section-title">Radar de Startups</div>
      ${startupsHtml}
    </div>
    <div class="section">
      <div class="section-title">Previsões para a Próxima Semana</div>
      ${previsoesHtml}
    </div>
    <div class="section">
      <div class="section-title">Distribuição por Categoria</div>
      <div>${categoriasHtml}</div>
    </div>
    <div class="footer">Gerado automaticamente pelo Inteli AI Intelligence Hub · Workflow 2</div>
  </div>
</body>
</html>`;

return [{
  json: {
    semana: dadosSemana.semana,
    total_artigos: dadosSemana.total_artigos,
    por_categoria: dadosSemana.por_categoria,
    por_sentimento: dadosSemana.por_sentimento,
    top10: dadosSemana.top10,
    oportunidades_unicas: dadosSemana.oportunidades_unicas,
    analise,
    html_completo: htmlCompleto
  }
}];

// PREPARA LINHA DE RESUMO PARA O GOOGLE SHEETS
const d = $input.first().json;
const a = d.analise || {};

const tendencias = (a.principais_tendencias || []).map(t => t.titulo).join(' | ');
const startups = (a.radar_startups || []).map(s => s.oportunidade).join(' | ');
const previsoes = (a.previsoes_proxima_semana || []).map(p => p.previsao).join(' | ');
const categorias = Object.entries(d.por_categoria || {}).map(([k,v]) => `${k}:${v}`).join(', ');

return [{ json: {
  semana: d.semana,
  total_artigos: d.total_artigos,
  positivos: d.por_sentimento?.positivo || 0,
  neutros: d.por_sentimento?.neutro || 0,
  negativos: d.por_sentimento?.negativo || 0,
  resumo_executivo: a.resumo_executivo || '',
  principais_tendencias: tendencias,
  radar_startups: startups,
  previsoes_proxima_semana: previsoes,
  categorias_distribuicao: categorias,
  data_geracao: new Date().toISOString()
}}];

const html = $input.first().json.html_completo;
const buffer = Buffer.from(html, 'utf-8');

return [{
  json: {},
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'text/html',
      fileName: `relatorio-${new Date().toISOString().split('T')[0]}.html`,
      fileExtension: 'html'
    }
  }
}];

// MONTA MENSAGEM SLACK
const d = $input.first().json;
const a = d.analise || {};

const tendencias = (a.principais_tendencias || []).map((t, i) =>
  `${i+1}. *${t.titulo}*
   ${t.analise}`
).join('

');

const startups = (a.radar_startups || []).map(s =>
  `• *${s.oportunidade}* — ${s.descricao}`
).join('
');

const previsoes = (a.previsoes_proxima_semana || []).map(p =>
  `• ${p.previsao}`
).join('
');

const categorias = Object.entries(d.por_categoria || {})
  .sort((a, b) => b[1] - a[1])
  .map(([k, v]) => `${k}: ${v}`)
  .join(' · ');

return [{ json: {
  mensagem: `📊 *Inteli AI Intelligence Hub — Relatório Semanal*
📅 Semana de ${d.semana}
📰 *${d.total_artigos} artigos* analisados | 🟢 ${d.por_sentimento?.positivo || 0} positivos

---

📋 *RESUMO EXECUTIVO*
${a.resumo_executivo}

---

📈 *PRINCIPAIS TENDÊNCIAS*
${tendencias}

---

💼 *RADAR DE STARTUPS*
${startups}

---

🔮 *PREVISÕES PARA A PRÓXIMA SEMANA*
${previsoes}

---

📊 *Por categoria:* ${categorias}

_Relatório completo enviado por email_ 📧`
}}];

